// Pré-computa o base64 do PDF E monta o body completo da requisição OCR.
// Roda direto após o Switch[PDF], então o item ainda tem o binário.
// Passar o body como objeto JS (e não template string) evita qualquer
// corrupção do base64 gigante (~10MB) na interpolação do n8n.
const items = $input.all();
const out = [];

const ctx = $('Set File ID - to Context').first().json;
const fileTitle = ctx?.file_title || 'document';
const fileId = ctx?.file_id || '(sem id)';

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.binary) {
    throw new Error('Sem binário no input.');
  }
  const binaryKey = item.binary.data ? 'data' : Object.keys(item.binary)[0];
  let buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);

  // Detecta PDF criptografado / protegido. Mesmo sem senha de abertura,
  // PDFs com /Encrypt fazem o Azure OpenAI retornar 500. Tentamos remover
  // a criptografia em memoria via pdf-lib (ignoreEncryption + re-save).
  const headSample = buffer.slice(0, Math.min(buffer.length, 8192)).toString('latin1');
  const tailSample = buffer.slice(-Math.min(buffer.length, 8192)).toString('latin1');
  const isEncrypted = /\/Encrypt[\s<\d]/.test(headSample) || /\/Encrypt[\s<\d]/.test(tailSample);
  let decrypted = false;
  if (isEncrypted) {
    try {
      const { PDFDocument } = require('pdf-lib');
      const srcDoc = await PDFDocument.load(buffer, { ignoreEncryption: true });
      const cleanDoc = await PDFDocument.create();
      const pageIdx = srcDoc.getPageIndices();
      const copied = await cleanDoc.copyPages(srcDoc, pageIdx);
      copied.forEach(p => cleanDoc.addPage(p));
      const cleanBytes = await cleanDoc.save({ useObjectStreams: false });
      buffer = Buffer.from(cleanBytes);
      decrypted = true;
    } catch (err) {
      // Best-effort: se nao conseguirmos remover a protecao, seguimos com o buffer
      // original. A Azure (Responses API com input_file) costuma aceitar muitos PDFs
      // que o pdf-lib nao consegue reabrir. Apenas registramos o motivo.
      console.warn('[Prepare PDF Base64] pdf-lib falhou ao desencriptar "' + fileTitle + '" (file_id=' + fileId + '): ' + (err && err.message ? err.message : String(err)));
    }
  }

  const base64 = buffer.toString('base64');

  // Azure OpenAI Responses API (suporta PDF nativamente via input_file).
  // Chat Completions NAO aceita PDF como anexo - era por isso que o OCR voltava vazio.
  // IMPORTANTE: na Azure a Responses API NAO usa /deployments/{name}/ no path;
  // o deployment vai como "model" no body.
  const ocrBody = {
    model: 'gpt-5.4-mini',
    input: [
      {
        role: 'system',
        content: [
          { type: 'input_text', text: 'Voce e um OCR. Extraia TODO o texto visivel do documento PDF anexado, preservando ordem de leitura, listas, tabelas e quebras de paragrafo. Nao resuma, nao comente, nao adicione cabecalhos. Retorne apenas o texto bruto extraido. Se uma pagina estiver totalmente em branco ou ilegivel, escreva [PAGINA EM BRANCO].' }
        ]
      },
      {
        role: 'user',
        content: [
          { type: 'input_text', text: 'Transcreva o conteudo deste PDF.' },
          {
            type: 'input_file',
            filename: fileTitle + '.pdf',
            file_data: 'data:application/pdf;base64,' + base64,
          },
        ],
      },
    ],
    max_output_tokens: 16000,
  };

  item.json = {
    ...item.json,
    pdf_size_bytes: buffer.length,
    pdf_base64_length: base64.length,
    pdf_was_encrypted: isEncrypted,
    pdf_decrypted_inline: decrypted,
    ocr_body: ocrBody,
  };
  out.push(item);
}

return out;

parameters.query:
DELETE FROM zanaflex_documents 
WHERE metadata->>'file_id' = '{{ $json.file_id }}'
AND (metadata->>'session_id' IS NULL OR metadata->>'session_id' = '');

-- Schema alinhado com migrations/008_rag_documents_acl.sql
-- (não dropa as tabelas — migrations 006-014 são fonte da verdade)

CREATE EXTENSION IF NOT EXISTS vector;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE IF NOT EXISTS zanaflex_document_metadata (
  file_id      TEXT PRIMARY KEY,
  title        TEXT,
  code         TEXT,
  url          TEXT,
  source       TEXT,
  mime_type    TEXT,
  schema       JSONB,
  category_id  UUID,
  session_id   TEXT,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_zanaflex_meta_category ON zanaflex_document_metadata(category_id);
CREATE INDEX IF NOT EXISTS idx_zanaflex_meta_code     ON zanaflex_document_metadata(code);
CREATE INDEX IF NOT EXISTS zanaflex_idx_doc_metadata_session ON zanaflex_document_metadata(session_id);

CREATE TABLE IF NOT EXISTS zanaflex_document_rows (
  id          BIGSERIAL PRIMARY KEY,
  dataset_id  TEXT NOT NULL REFERENCES zanaflex_document_metadata(file_id) ON DELETE CASCADE,
  row_data    JSONB NOT NULL,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_zanaflex_rows_dataset ON zanaflex_document_rows(dataset_id);

CREATE TABLE IF NOT EXISTS zanaflex_chat_message (
  id SERIAL PRIMARY KEY,
  session_id TEXT NOT NULL,
  message JSONB NOT NULL,
  created_at TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS zanaflex_idx_chat_message_session_id ON zanaflex_chat_message(session_id);

-- 1. Remove Histórico de Chat Antigo (Removido o '*')
DELETE FROM zanaflex_chat_message;

-- 2. Remove Vetores Antigos
DELETE FROM zanaflex_documents 
WHERE metadata->>'session_id' IS NOT NULL;

-- 3. Remove Arquivos/Metadados Antigos
DELETE FROM zanaflex_document_metadata 
WHERE session_id IS NOT NULL;

