const data = $input.all();

for (const item of data) {
  // O comando "Reflect" força a deleção sem o editor reclamar de Tipos
  Reflect.deleteProperty(item, 'binary');
}

return data;

// 1. Acessa os dados de entrada
const firstItem = (typeof items !== 'undefined' && items.length > 0) ? items[0] : $input.first();

// 2. Extrai e faz o PARSE do texto JSON
let inputData = [];

if (firstItem.json.concatenated_data) {
    try {
        // Transformamos o texto "[{...}]" em um Array real via JSON.parse
        inputData = JSON.parse(firstItem.json.concatenated_data);
    } catch (e) {
        // Se falhar o parse, tenta usar o json direto caso já seja objeto
        inputData = firstItem.json.data || [];
    }
} else if (Array.isArray(firstItem.json)) {
    inputData = firstItem.json;
} else if (firstItem.json.data) {
    inputData = firstItem.json.data;
}

// Se o inputData não for uma lista (array), forçamos ser uma lista vazia para não quebrar o loop
if (!Array.isArray(inputData)) {
    inputData = []; 
}

// --- INÍCIO DO PROCESSAMENTO ---

const cleanData = [];

for (const row of inputData) {
  // Garante que row é um objeto válido
  if (typeof row !== 'object' || row === null) continue;

  const cleanItem = {};
  let textForRag = ""; 

  // Como os dados já têm as chaves corretas (ex: "Empresa", "CNPJ"), 
  // iteramos direto sobre elas
  for (const key in row) {
    const value = row[key];

    // Verifica se o valor não é nulo, indefinido ou vazio
    if (value !== undefined && value !== null && value !== '') {
      cleanItem[key] = value;
      // Monta o texto para o RAG dinamicamente
      textForRag += `${key}: ${value}. `;
    }
  }

  // Se o objeto não estiver vazio, adiciona a propriedade de texto e insere no array final
  if (Object.keys(cleanItem).length > 0) {
    cleanItem.text_for_rag = textForRag.trim();
    cleanData.push({ json: cleanItem });
  }
}

return cleanData;

// Limpeza de Docs - lida com saídas dos nós Extract PDF Text (campo "text")
// e Extract Document Text (campo "data"). Detecta PDFs sem camada de texto
// (ex.: digitalizações geradas por PDFCreator) e sinaliza claramente.

const out = [];

for (const item of $input.all()) {
  // 1. Descobre onde está o conteúdo bruto
  const sourceField = item.json.text != null ? 'text'
                    : item.json.data != null ? 'data'
                    : null;

  if (!sourceField) {
    // Nada para limpar — repassa como veio
    out.push(item);
    continue;
  }

  const raw = String(item.json[sourceField] ?? '');

  // 2. Remove TUDO que não é letra, número, pontuação, espaço ou quebra de linha
  //    (mata binários que vazam de PDFs problemáticos)
  let cleanText = raw.replace(/[^\p{L}\p{N}\p{P}\p{Z}\n]/gu, '');

  // 3. Remove sequências de escape Unicode incompletas
  cleanText = cleanText.replace(/\\u/g, '');

  // 4. Normaliza espaços/quebras de linha excessivas para medir conteúdo real
  const meaningful = cleanText.replace(/\s+/g, '').trim();

  // 5. Detecta PDF sem texto extraível (apenas \n\n\n... do pdf-parse).
  //    Esses arquivos quase sempre são digitalizações/imagens dentro do PDF
  //    e precisam de OCR para serem indexados.
  if (meaningful.length < 20) {
    const fileTitle = $('Set File ID - to Context')?.first()?.json?.file_title ?? '(desconhecido)';
    const fileId    = $('Set File ID - to Context')?.first()?.json?.file_id    ?? '(sem id)';
    const ocrUsed   = item.json.ocr_used === true;
    throw new Error(
      `PDF sem texto utilizavel: "${fileTitle}" (file_id=${fileId}). ` +
      (ocrUsed
        ? `OCR via Azure OpenAI tambem nao retornou texto. Verifique se o deployment tem suporte a visao/PDF e se o arquivo nao esta protegido/corrompido.`
        : `O arquivo provavelmente e uma digitalizacao/imagem sem camada de texto e o branch OCR nao foi acionado.`)
    );
  }

  // 6. Limite de segurança (50k chars) e grava no MESMO campo de origem,
  //    além de em "data" para compatibilidade com o Default Data Loader.
  const finalText = cleanText.substring(0, 50000);
  item.json[sourceField] = finalText;
  item.json.data = finalText;

  out.push(item);
}

return out;
